import React, { useEffect, useState } from "react";
import { PageShell } from "@/components/orderly/PageShell";
import { OdsCheckbox } from "@/components/orderly/OdsCheckbox";
import { Menu, Info } from "lucide-react";
import { useTranslation } from "@/i18n";
import { storageKey } from "@/utils/storage";

const DEFAULT_MENU_ITEMS = [
  "Portfolio",
  "Markets",
  "Trade",
  "Swap",
  "Earn",
  "Rewards",
  "Campaigns",
  "Leaderboard",
  "Referral",
  "Analytics",
];

export default function NavigationMenusPage() {
  const { t } = useTranslation();
  const [enabledMenus, setEnabledMenus] =
    useState<string[]>(DEFAULT_MENU_ITEMS);
  const [customMenus, setCustomMenus] = useState<string>("");
  const [enableCampaigns, setEnableCampaigns] = useState<boolean>(false);
  const [toast, setToast] = useState<string | null>(null);

  useEffect(() => {
    const savedMenus = localStorage.getItem(storageKey("orderlyEnabledMenus"));
    if (savedMenus) {
      setEnabledMenus(
        savedMenus
          .split(",")
          .map(m => m.trim())
          .filter(Boolean)
      );
    }
    const savedCustom = localStorage.getItem(storageKey("orderlyCustomMenus"));
    if (savedCustom !== null) {
      setCustomMenus(savedCustom);
    }
    setEnableCampaigns(
      localStorage.getItem(storageKey("orderlyEnableCampaigns")) === "true"
    );
  }, []);

  function showToast(message: string) {
    setToast(message);
    setTimeout(() => setToast(null), 3000);
  }

  function toggleMenu(menu: string) {
    const newEnabled = enabledMenus.includes(menu)
      ? enabledMenus.filter(m => m !== menu)
      : [...enabledMenus, menu];
    setEnabledMenus(newEnabled);
    localStorage.setItem(
      storageKey("orderlyEnabledMenus"),
      newEnabled.join(",")
    );
    showToast(t("navigationMenus.toastUpdated"));
  }

  function handleCustomMenusChange(e: React.ChangeEvent<HTMLTextAreaElement>) {
    setCustomMenus(e.target.value);
  }

  function handleSaveCustomMenus() {
    localStorage.setItem(storageKey("orderlyCustomMenus"), customMenus);
    showToast(t("navigationMenus.toastSaved"));
  }

  function handleCampaignsToggle(checked: boolean) {
    setEnableCampaigns(checked);
    localStorage.setItem(storageKey("orderlyEnableCampaigns"), String(checked));
    showToast(
      checked
        ? t("navigationMenus.toastCampaignsEnabled")
        : t("navigationMenus.toastCampaignsDisabled")
    );
  }

  return (
    <PageShell pageTitle={t("navigationMenus.title")}>
      <div className="space-y-5">
        <div className="rounded-xl border border-(--line-subtle) bg-(--bg-surface-primary) p-6">
          <div className="mb-5 flex items-center gap-2">
            <div className="flex h-8 w-8 items-center justify-center rounded-md bg-[rgba(188,135,255,0.12)] text-(--fg-brand)">
              <Menu className="h-4 w-4" />
            </div>
          </div>

          <div className="mb-6">
            <label className="mb-3 block text-sm text-(--fg-secondary)">
              {t("navigationMenus.enabledItems")}
            </label>
            <div className="grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-5">
              {DEFAULT_MENU_ITEMS.map(menu => (
                <label
                  key={menu}
                  className="flex cursor-pointer items-center gap-2 rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) px-3 py-2.5 transition-colors hover:bg-(--bg-hover)"
                >
                  <OdsCheckbox
                    checked={enabledMenus.includes(menu)}
                    onCheckedChange={() => toggleMenu(menu)}
                  />
                  <span className="text-sm text-(--fg-primary)">{menu}</span>
                </label>
              ))}
            </div>
          </div>

          <div className="mb-6">
            <label className="mb-1.5 block text-sm text-(--fg-secondary)">
              {t("navigationMenus.customJSON")}
            </label>
            <textarea
              value={customMenus}
              onChange={handleCustomMenusChange}
              placeholder={t("navigationMenus.customJSONPlaceholder")}
              rows={4}
              className="w-full rounded-lg border border-(--line-subtle) bg-(--bg-input) px-3 py-2 text-sm text-(--fg-primary) outline-none transition-colors focus:border-(--line-brand) resize-none font-mono"
            />
            <p className="mt-1.5 text-xs text-(--fg-secondary)">
              {t("navigationMenus.customJSONHint")}
            </p>
            <button
              type="button"
              onClick={handleSaveCustomMenus}
              className="mt-3 inline-flex items-center gap-2 rounded-full px-5 py-2.5 text-sm font-medium text-(--fg-primary) transition-opacity hover:opacity-90"
              style={{ background: "var(--bg-brand-grad)" }}
            >
              {t("navigationMenus.saveCustomMenus")}
            </button>
          </div>

          <div className="mb-4 flex items-start gap-3 rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) p-4">
            <OdsCheckbox
              id="enableCampaigns"
              checked={enableCampaigns}
              onCheckedChange={checked =>
                handleCampaignsToggle(checked === true)
              }
              className="mt-1"
            />
            <div className="flex-1">
              <label
                htmlFor="enableCampaigns"
                className="cursor-pointer text-sm font-medium text-(--fg-primary)"
              >
                {t("navigationMenus.enableCampaigns")}
              </label>
              <p className="mt-0.5 text-xs text-(--fg-secondary)">
                {t("navigationMenus.campaignsDescription")}
              </p>
            </div>
          </div>

          <div className="rounded-lg border border-[rgba(72,189,255,0.25)] bg-[rgba(72,189,255,0.08)] p-4">
            <div className="flex items-start gap-3">
              <Info className="mt-0.5 h-5 w-5 shrink-0 text-[rgba(255,255,255,0.8)]" />
              <div>
                <h4 className="mb-2 text-sm font-bold text-[rgba(255,255,255,0.9)]">
                  {t("navigationMenus.aboutCampaigns")}
                </h4>
                <div className="space-y-1 text-xs text-(--fg-secondary)">
                  <p>{t("navigationMenus.campaignDescription")}</p>
                  <ul className="list-disc space-y-1 pl-4">
                    <li>{t("navigationMenus.campaignBanners")}</li>
                    <li>{t("navigationMenus.campaignLinks")}</li>
                  </ul>
                  <p className="pt-1 text-[rgba(255,255,255,0.7)]">
                    {t("navigationMenus.campaignOptional")}
                  </p>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {toast && (
        <div className="fixed bottom-5 left-1/2 z-100 -translate-x-1/2 rounded-full border border-(--line-brand) bg-(--bg-surface-primary) px-5 py-2.5 text-sm font-medium text-(--fg-primary) shadow-xl">
          {toast}
        </div>
      )}
    </PageShell>
  );
}
